import { Component, OnInit } from '@angular/core';
import { RouterLink } from '@angular/router';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { NavbarComponent } from '../../components/navbar/navbar.component';
import { FooterComponent } from '../../components/footer/footer.component';
import { BookCardComponent, BookCard } from '../../components/book-card/book-card.component';

@Component({
  selector: 'app-catalogue',
  standalone: true,
  imports: [RouterLink, CommonModule, FormsModule, NavbarComponent, FooterComponent, BookCardComponent],
  templateUrl: './catalogue.component.html',
})
export class CatalogueComponent implements OnInit {
  searchQuery = '';
  selectedCategory = 'Tous';
  selectedCondition = '';
  books: BookCard[] = [];
  filteredBooks: BookCard[] = [];
  total = 0;

  categories = ['Tous', 'Littérature', 'Éducation', 'Sciences', 'Histoire', 'Technologie', 'Art & Culture', 'Philosophie', 'Économie'];

  ngOnInit() {
    this.books = this.getMockBooks(12);
    this.filteredBooks = this.books;
    this.total = this.books.length;
  }

  filter() {
    this.filteredBooks = this.books.filter(b => {
      const matchQ = !this.searchQuery || b.title.toLowerCase().includes(this.searchQuery.toLowerCase()) || b.author.toLowerCase().includes(this.searchQuery.toLowerCase());
      const matchCond = !this.selectedCondition || b.condition === this.selectedCondition;
      return matchQ && matchCond;
    });
    this.total = this.filteredBooks.length;
  }

  getMockBooks(count: number): BookCard[] {
    const data = [
      { t: 'Mathématiques Terminale S', a: 'Seydou Traoré', p: 12000, c: 'like_new' },
      { t: 'L\'enfant noir', a: 'Camara Laye', p: 8500, c: 'good' },
      { t: 'Le Monde s\'effondre', a: 'Chinua Achebe', p: 7500, c: 'new' },
      { t: 'Histoire Générale de l\'Afrique', a: 'Joseph Ki-Zerbo', p: 18000, c: 'good' },
      { t: 'Une si longue lettre', a: 'Mariama Bâ', p: 6500, c: 'fair' },
      { t: 'Médecine Traditionnelle Africaine', a: 'Dr. Anta Diop', p: 25000, c: 'new' },
      { t: 'Introduction à la Biologie', a: 'Prof. Aminata Diallo', p: 15000, c: 'good' },
      { t: 'Programmation Python', a: 'Ousmane Tall', p: 22000, c: 'new' },
      { t: 'Art Contemporain Africain', a: 'Fatou Ndiaye', p: 16500, c: 'like_new' },
      { t: 'Physique-Chimie 1ère S', a: 'Dr. Mamadou Fall', p: 9800, c: 'good' },
      { t: 'Philosophie Africaine', a: 'Kwame Nkrumah', p: 13500, c: 'good' },
      { t: 'Économie du Développement', a: 'Samir Amin', p: 19500, c: 'fair' },
    ];
    return Array.from({ length: Math.min(count, data.length) }, (_, i) => ({
      id: i + 1,
      title: data[i].t,
      author: data[i].a,
      price: data[i].p,
      condition: data[i].c,
      book_type: i < 2 ? 'textbook' : 'novel',
      images: [{ url: `https://picsum.photos/seed/cat${i+10}/300/400`, is_primary: true }],
      seller: { first_name: 'Vendeur', last_name: `${i+1}`, phone: '+224000000000', address: ['Dakar, Sénégal', 'Conakry', 'Bamako', 'Ouagadougou'][i % 4] },
      is_available: true,
    }));
  }
}
